import { describe, it, expect } from "vitest";
import { quote, claim } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("quote", () => {
    it.todo("empty item list returns premium of 5 G (processing fee only)");
    it.todo("single plain sword returns 105 G (100 base + 5 fee)");
    it.todo("single plain amulet returns 65 G (60 base + 5 fee)");
    it.todo("single plain staff returns 85 G (80 base + 5 fee)");
    it.todo("single plain potion returns 45 G (40 base + 5 fee)");
    it.todo("single rune component returns 30 G (25 base + 5 fee)");
    it.todo("two different items sums their base premiums (sword + amulet → 165 G)");
    it.todo("three alike components form a building block (3 runes → 65 G)");
    it.todo("four alike components do not form a block (4 runes → 105 G)");
    it.todo("two different component types do not form a block (2 runes + 1 moonstone → 80 G)");
    it.todo("cursed item adds 50% surcharge on that item's base premium");
    it.todo("highly enchanted item (enchantment ≥ 5) adds 30% surcharge");
    it.todo("long-standing customer (≥ 2 years) gets 20% loyalty discount on policy total");
    it.todo("first insurance adds 10% surcharge per item");
    it.todo("follow-up contract gives 15% discount on policy total");
    it.todo("premium rounded up in MHPCO's favor");
    it.todo("unknown item type causes error");
  });

  describe("claim", () => {
    it.todo("standard damage minus 100 G deductible (sword damage 500 → payout 400)");
    it.todo("damage to enchantment ≥ 8 item reimbursed at 50% then deductible");
    it.todo("damage to dragon-material item fully reimbursed then deductible");
    it.todo("payout capped at 2× insurance sum");
    it.todo("deductible applies per damage event (multi-item damage)");
    it.todo("claim with item not in policy causes error");
    it.todo("claim with negative damage amount causes error");
  });
});

